/**
 * Gateway shared types — dependency port, connection state, and shared abstractions.
 *
 * GatewayDeps is the port type: all external capabilities the gateway needs
 * are expressed as function signatures, not module imports.
 */
import type { Surreal, RecordId } from "surrealdb";
import type { ServerConfig } from "../runtime/config";
import type { SseRegistry } from "../streaming/sse-registry";

// ---------------------------------------------------------------------------
// Connection state machine — pure states, no mutable fields
// ---------------------------------------------------------------------------

export type ConnectionState = "connecting" | "authenticating" | "active" | "closed";

// ---------------------------------------------------------------------------
// GatewayConnection — per-connection context after authentication
// ---------------------------------------------------------------------------

export type GatewayConnection = {
  readonly connectionId: string;
  readonly state: ConnectionState;
  readonly identityId?: string;
  readonly workspaceId?: string;
  readonly agentId?: string;
  readonly protocolVersion?: number;
  readonly connectedAt: Date;
};

// ---------------------------------------------------------------------------
// Stream event type for session event subscriptions
// ---------------------------------------------------------------------------

export type StreamEvent = {
  readonly type: string;
  readonly data: unknown;
};

// ---------------------------------------------------------------------------
// GatewayDeps — the port type for all gateway dependencies
//
// Every external capability is a function signature. The gateway never
// imports IO modules directly. Dependencies are injected at the composition root.
// ---------------------------------------------------------------------------

export type GatewayDeps = {
  readonly surreal: Surreal;
  readonly config: ServerConfig;
  readonly sseRegistry: SseRegistry;

  // Identity & workspace resolution
  readonly lookupIdentity: (token: string) => Promise<{ identityId: string; workspaceId: string } | undefined>;
  readonly lookupWorkspace: (workspaceId: string) => Promise<{ id: string; name: string } | undefined>;

  // Agent session management
  readonly listSessions: (workspaceId: string) => Promise<ReadonlyArray<{ id: string; agent: string; status: string }>>;
  readonly getSessionHistory: (sessionId: string) => Promise<ReadonlyArray<{ role: string; text: string }>>;
  readonly patchSession: (sessionId: string, patch: Record<string, unknown>) => Promise<void>;

  // Context & task operations
  readonly loadContext: (workspaceId: string, taskDescription: string) => Promise<{
    decisions: number;
    constraints: number;
    learnings: number;
    observations: number;
  }>;
  readonly assignTask: (workspaceId: string, task: string) => Promise<{ runId: string; sessionId: string }>;
  readonly evaluateIntent: (workspaceId: string, action: string) => Promise<{ authorized: boolean }>;

  // Tool registry
  readonly listGrantedTools: (workspaceId: string) => Promise<ReadonlyArray<{ name: string; description: string }>>;

  // Tracing
  readonly recordTrace: (trace: { connectionId: string; method: string; durationMs: number; error?: string }) => Promise<void>;

  // Session event subscription
  readonly subscribeToSessionEvents: (sessionId: string) => AsyncIterable<StreamEvent>;
};

