 34→/** Generate an Ed25519 key pair and sign a nonce. Returns connect params. */
 35→async function createDeviceAuth(nonce: string) {
 36→  const keyPair = await crypto.subtle.generateKey("Ed25519", true, [
 37→    "sign",
 38→    "verify",
 39→  ]);
 40→  const publicKeyRaw = await crypto.subtle.exportKey(
 41→    "raw",
 42→    keyPair.publicKey,
 43→  );
 44→  const publicKeyBase64 = Buffer.from(publicKeyRaw).toString("base64");
 45→
 46→  const nonceBytes = Buffer.from(nonce, "base64");
 47→  const signature = await crypto.subtle.sign(
 48→    "Ed25519",
 49→    keyPair.privateKey,
 50→    nonceBytes,
 51→  );
 52→  const signatureBase64 = Buffer.from(signature).toString("base64");
 53→
 54→  return {
 55→    publicKeyBase64,
 56→    signatureBase64,
 57→    deviceId: `dev-${crypto.randomUUID().slice(0, 8)}`,
 58→  };
 59→}
