278→// --- Test Data Seeding Helpers ---
279→
280→/**
281→ * Seed decisions in a workspace for context injection testing.
282→ * Returns the created decision RecordIds.
283→ */
284→export async function seedDecisions(
285→  surreal: Surreal,
286→  workspaceRecord: RecordId<"workspace", string>,
287→  projectRecord: RecordId<"project", string>,
288→  count: number,
289→): Promise<RecordId<"decision", string>[]> {
290→  const records: RecordId<"decision", string>[] = [];
291→  for (let i = 0; i < count; i++) {
292→    const decisionRecord = new RecordId("decision", crypto.randomUUID());
293→    await surreal.create(decisionRecord).content({
294→      summary: `Test decision ${i + 1}`,
295→      status: "confirmed",
296→      workspace: workspaceRecord,
297→      created_at: new Date(),
298→      updated_at: new Date(),
299→    });
300→    await surreal
301→      .relate(
302→        decisionRecord,
303→        new RecordId("belongs_to", crypto.randomUUID()),
304→        projectRecord,
305→        { added_at: new Date() },
306→      )
307→      .output("after");
308→    records.push(decisionRecord);
309→  }
310→  return records;
311→}
