345→/**
346→ * Seed a project in a workspace. Returns the project RecordId.
347→ */
348→export async function seedProject(
349→  surreal: Surreal,
350→  workspaceRecord: RecordId<"workspace", string>,
351→  name: string,
352→): Promise<RecordId<"project", string>> {
353→  const projectRecord = new RecordId("project", crypto.randomUUID());
354→  await surreal.create(projectRecord).content({
355→    name,
