  1→/**
  2→ * Walking Skeleton — OpenClaw Gateway Protocol
  3→ *
  4→ * Validates the full gateway pipeline end-to-end:
  5→ * WS connect → skeleton auth → agent method → orchestrator →
  6→ * token streaming via WS events → session completion → trace recorded
  7→ *
  8→ * Driving port: WebSocket at /api/gateway
  9→ * Scenarios: WS-1 through WS-5
 10→ */
 11→import { describe, expect, it } from "bun:test";
 12→import { RecordId } from "surrealdb";
 13→import { setupAcceptanceSuite } from "../acceptance-test-kit";
 14→import {
 15→  connectGateway,
 16→  connectGatewayWithSkeletonAuth,
 17→  isDoneEvent,
 18→  isAssistantEvent,
 19→  seedDecisions,
 20→  seedConstraints,
 21→  seedProject,
 22→} from "./gateway-test-kit";
 23→
 24→const getRuntime = setupAcceptanceSuite("gateway-walking-skeleton");
 25→
 26→describe("Gateway Walking Skeleton", () => {
 27→  // WS-1: WebSocket upgrade succeeds (AC-0.1)
 28→  // When a client sends an HTTP upgrade request to "/api/gateway"
 29→  // Then Brain upgrades the connection to WebSocket
 30→  it("WS-1: WebSocket upgrade to /api/gateway succeeds", async () => {
 31→    const { baseUrl } = getRuntime();
 32→    const client = await connectGateway(baseUrl);
 33→
 34→    expect(client.isOpen()).toBe(true);
 35→
 36→    client.close();
 37→  });
 38→
 39→  // WS-5: Error path — proves /api/gateway rejects non-WebSocket requests.
 40→  // This is part of the walking skeleton's driving-port validation: only WS upgrade is allowed.
 41→  it("WS-5: HTTP GET to /api/gateway returns 426 Upgrade Required", async () => {
 42→    const { baseUrl } = getRuntime();
 43→    const res = await fetch(`${baseUrl}/api/gateway`);
 44→
 45→    expect(res.status).toBe(426);
 46→  });
 47→
 48→  // WS-2: Agent method returns runId with context summary (AC-0.2)
 49→  // Given a WebSocket connection with skeleton identity
 50→  // And workspace has 2 decisions and 1 constraint
 51→  // When client sends agent method
 52→  // Then Brain responds with runId, sessionId, contextSummary matching seeded data
 53→  it("WS-2: agent method returns runId with context summary", async () => {
 54→    const { baseUrl, surreal } = getRuntime();
 55→
 56→    // Seed workspace with known data for context injection verification.
 57→    // The skeleton auth creates a workspace — we need to seed into it.
 58→    // For walking skeleton, we use a hardcoded workspace ID matching the skeleton identity.
 59→    const workspaceRecord = new RecordId("workspace", "skeleton-test-ws");
 60→    const project = await seedProject(surreal, workspaceRecord, "Gateway Test Project");
 61→    await seedDecisions(surreal, workspaceRecord, project, 2);
 62→    await seedConstraints(surreal, workspaceRecord, project, 1);
 63→
 64→    const client = await connectGatewayWithSkeletonAuth(baseUrl);
 65→
 66→    const response = await client.request("agent", {
 67→      task: "implement auth module",
 68→    });
 69→
 70→    expect(response.ok).toBe(true);
 71→
 72→    const payload = response.payload as {
 73→      runId: string;
 74→      sessionId: string;
 75→      contextSummary: {
 76→        decisions: number;
 77→        constraints: number;
 78→        learnings: number;
 79→        observations: number;
 80→      };
 81→    };
 82→
 83→    // Verify response shape
 84→    expect(payload.runId).toBeDefined();
 85→    expect(typeof payload.runId).toBe("string");
 86→    expect(payload.sessionId).toBeDefined();
 87→    expect(typeof payload.sessionId).toBe("string");
 88→
 89→    // Verify context injection matches seeded data
 90→    expect(payload.contextSummary.decisions).toBe(2);
 91→    expect(payload.contextSummary.constraints).toBe(1);
 92→    expect(payload.contextSummary.learnings).toBe(0);
 93→    expect(payload.contextSummary.observations).toBe(0);
 94→
 95→    client.close();
 96→  });
 97→
 98→  // WS-3: Token events stream with seq numbers (AC-0.3)
 99→  // Given an active agent session via the gateway
100→  // When the orchestrator produces agent_token events
101→  // Then the client receives event frames with monotonically increasing seq
102→  it("WS-3: token events stream with monotonically increasing seq numbers", async () => {
103→    const { baseUrl } = getRuntime();
104→    const client = await connectGatewayWithSkeletonAuth(baseUrl);
105→
106→    // Submit work to start streaming
107→    const agentRes = await client.request("agent", {
108→      task: "say hello",
109→    });
110→    expect(agentRes.ok).toBe(true);
111→
112→    // Collect events until we see the done event
113→    const events = await client.collectEvents(isDoneEvent, 30_000);
114→
115→    // Must have received at least one assistant stream event (token delta)
116→    const assistantEvents = events.filter(isAssistantEvent);
117→    expect(assistantEvents.length).toBeGreaterThan(0);
118→
119→    // Verify monotonically increasing seq numbers
120→    const seqNumbers = events
121→      .filter((e) => e.seq !== undefined)
122→      .map((e) => e.seq!);
123→    for (let i = 1; i < seqNumbers.length; i++) {
124→      expect(seqNumbers[i]).toBeGreaterThan(seqNumbers[i - 1]);
125→    }
126→
127→    client.close();
128→  });
129→
130→  // WS-4: Session completes with done event (AC-0.3 completion)
131→  // Given a streaming agent session
132→  // When the agent finishes execution
133→  // Then a lifecycle event with phase "done" is received
134→  it("WS-4: session completes with lifecycle done event", async () => {
135→    const { baseUrl } = getRuntime();
136→    const client = await connectGatewayWithSkeletonAuth(baseUrl);
137→
138→    const agentRes = await client.request("agent", {
139→      task: "say hello world",
140→    });
141→    expect(agentRes.ok).toBe(true);
142→
143→    // Wait specifically for the done event using predicate
144→    const doneEvent = await client.waitForEvent(isDoneEvent, 30_000);
145→
146→    // Verify done event structure
147→    const payload = doneEvent.payload as {
148→      stream: string;
149→      data: { phase: string };
150→    };
151→    expect(payload.stream).toBe("lifecycle");
152→    expect(payload.data.phase).toBe("done");
153→
154→    client.close();
155→  });
156→});
