  3→-- BM25 full-text search analyzer (required before any FULLTEXT index)
  4→DEFINE ANALYZER OVERWRITE entity_search
  5→  TOKENIZERS blank, class, camel, punct
  6→  FILTERS snowball(english), lowercase;
  7→
  8→DEFINE TABLE conversation SCHEMAFULL;
  9→DEFINE FIELD createdAt ON conversation TYPE datetime;
 10→DEFINE FIELD updatedAt ON conversation TYPE datetime;
 11→DEFINE FIELD workspace ON conversation TYPE record<workspace>;
 12→DEFINE FIELD source ON conversation TYPE option<string>;
 13→DEFINE FIELD timestamp ON conversation TYPE option<datetime>;
 14→DEFINE FIELD messages ON conversation TYPE option<array<record<message>>>;
 15→DEFINE FIELD title ON conversation TYPE option<string>;
 16→DEFINE FIELD title_source ON conversation TYPE option<string> ASSERT $value = NONE OR $value IN ["message", "entity"];
 17→DEFINE FIELD discusses ON conversation TYPE option<record<project | person | feature | task | decision | question | observation | suggestion>>;
 18→DEFINE INDEX conversation_createdAt ON conversation FIELDS createdAt;
 19→DEFINE INDEX conversation_workspace ON conversation FIELDS workspace;
 20→
 21→DEFINE TABLE message SCHEMAFULL;
 22→DEFINE FIELD conversation ON message TYPE record<conversation>;
 23→DEFINE FIELD role ON message TYPE string ASSERT $value IN ["user", "assistant"];
 24→DEFINE FIELD text ON message TYPE string;
 25→DEFINE FIELD createdAt ON message TYPE datetime;
 26→DEFINE FIELD suggestions ON message TYPE option<array<string>>;
 27→DEFINE FIELD clientMessageId ON message TYPE option<string>;
 28→DEFINE INDEX message_conversation_createdAt ON message FIELDS conversation, createdAt;
 29→DEFINE INDEX OVERWRITE idx_message_fulltext ON message FIELDS text FULLTEXT ANALYZER entity_search BM25(1.2, 0.75);
 30→
 31→DEFINE TABLE entity SCHEMAFULL;
