364→/**
365→ * Helper to check if an event is a "done" lifecycle event.
366→ * Used as predicate for collectEvents/waitForEvent to avoid brittle deep checks.
367→ */
368→export function isDoneEvent(event: EventFrame): boolean {
369→  const payload = event.payload as
370→    | { stream?: string; data?: { phase?: string } }
371→    | undefined;
372→  return (
373→    event.event === "agent.stream" &&
374→    payload?.stream === "lifecycle" &&
375→    payload?.data?.phase === "done"
376→  );
