/**
 * Gateway Protocol v3 — Frame types, parsing, and serialization.
 *
 * All functions are pure. No IO, no side effects, no imports from IO modules.
 * The protocol uses JSON text frames over WebSocket with three discriminants:
 * - "req"   — client-to-server request expecting a response
 * - "res"   — server-to-client response matching a request id
 * - "event" — server-to-client push notification (no request id needed)
 */

// ---------------------------------------------------------------------------
// Method names — all protocol methods the gateway recognizes
// ---------------------------------------------------------------------------

export type MethodName =
  | "connect"
  | "ping"
  | "agent"
  | "session.list"
  | "session.history"
  | "session.patch"
  | "context.load"
  | "tools.list"
  | "tools.grant";

// ---------------------------------------------------------------------------
// Error codes — protocol-level and business-level error classifications
// ---------------------------------------------------------------------------

export type ErrorCode =
  | "PARSE_ERROR"
  | "INVALID_PARAMS"
  | "METHOD_NOT_FOUND"
  | "AUTH_FAILED"
  | "AUTH_REQUIRED"
  | "FORBIDDEN"
  | "NOT_FOUND"
  | "RATE_LIMITED"
  | "INTERNAL_ERROR"
  | "PROTOCOL_MISMATCH"
  | "CONNECTION_CLOSED";

// ---------------------------------------------------------------------------
// Frame types — discriminated union on the "type" field
// ---------------------------------------------------------------------------

export type RequestFrame = {
  readonly type: "req";
  readonly id: string;
  readonly method: MethodName;
  readonly params?: unknown;
};

export type GatewayError = {
  readonly code: ErrorCode;
  readonly message: string;
  readonly details?: unknown;
};

export type ResponseFrame =
  | {
      readonly type: "res";
      readonly id: string;
      readonly ok: true;
      readonly payload?: unknown;
    }
  | {
      readonly type: "res";
      readonly id: string;
      readonly ok: false;
      readonly error: GatewayError;
    };

export type EventFrame = {
  readonly type: "event";
  readonly event: string;
  readonly payload?: unknown;
  readonly seq?: number;
};

export type GatewayFrame = RequestFrame | ResponseFrame | EventFrame;

// ---------------------------------------------------------------------------
// Pure parser — string to GatewayFrame | { error: string }
// ---------------------------------------------------------------------------

export function parseFrame(raw: string): GatewayFrame | { error: string } {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return { error: "Failed to parse JSON frame" };
  }

  if (typeof parsed !== "object" || parsed === null) {
    return { error: "Frame must be a JSON object" };
  }

  const obj = parsed as Record<string, unknown>;
  const frameType = obj.type;

  if (frameType === "req") {
    return parseRequestFrame(obj);
  }
  if (frameType === "res") {
    return parseResponseFrame(obj);
  }
  if (frameType === "event") {
    return parseEventFrame(obj);
  }

  return { error: `Unknown frame type: ${String(frameType)}` };
}

function parseRequestFrame(obj: Record<string, unknown>): RequestFrame | { error: string } {
  if (typeof obj.id !== "string") {
    return { error: "Request frame missing required field: id" };
  }
  if (typeof obj.method !== "string") {
    return { error: "Request frame missing required field: method" };
  }
  const frame: RequestFrame = {
    type: "req",
    id: obj.id,
    method: obj.method as MethodName,
    ...(obj.params !== undefined ? { params: obj.params } : {}),
  };
  return frame;
}

function parseResponseFrame(obj: Record<string, unknown>): ResponseFrame | { error: string } {
  if (typeof obj.id !== "string") {
    return { error: "Response frame missing required field: id" };
  }
  if (typeof obj.ok !== "boolean") {
    return { error: "Response frame missing required field: ok" };
  }

  if (obj.ok) {
    const frame: ResponseFrame = {
      type: "res",
      id: obj.id,
      ok: true,
      ...(obj.payload !== undefined ? { payload: obj.payload } : {}),
    };
    return frame;
  }

  const frame: ResponseFrame = {
    type: "res",
    id: obj.id,
    ok: false,
    error: obj.error as GatewayError,
  };
  return frame;
}

function parseEventFrame(obj: Record<string, unknown>): EventFrame | { error: string } {
  if (typeof obj.event !== "string") {
    return { error: "Event frame missing required field: event" };
  }
  const frame: EventFrame = {
    type: "event",
    event: obj.event,
    ...(obj.payload !== undefined ? { payload: obj.payload } : {}),
    ...(obj.seq !== undefined ? { seq: obj.seq as number } : {}),
  };
  return frame;
}

// ---------------------------------------------------------------------------
// Pure serializer — GatewayFrame to JSON string
// ---------------------------------------------------------------------------

export function serializeFrame(frame: GatewayFrame): string {
  return JSON.stringify(frame);
}

