 46→// ---------------------------------------------------------------------------
 47→// Error codes — protocol-level and business-level error classifications
 48→// ---------------------------------------------------------------------------
 49→
 50→export type ErrorCode =
 51→  // Protocol errors
 52→  | "invalid_frame"
 53→  | "unknown_method"
 54→  | "not_authenticated"
 55→  | "already_authenticated"
 56→  // Device auth errors (aligned with real protocol)
 57→  | "auth_failed"
 58→  | "DEVICE_AUTH_NONCE_REQUIRED"
 59→  | "DEVICE_AUTH_NONCE_MISMATCH"
 60→  | "DEVICE_AUTH_SIGNATURE_INVALID"
 61→  | "DEVICE_AUTH_SIGNATURE_EXPIRED"
 62→  | "DEVICE_AUTH_DEVICE_ID_MISMATCH"
 63→  | "DEVICE_AUTH_PUBLIC_KEY_INVALID"
 64→  | "AUTH_TOKEN_MISMATCH"
 65→  // Business errors
 66→  | "no_membership"
 67→  | "policy_violation"
 68→  | "budget_exceeded"
 69→  | "session_not_found"
 70→  | "method_not_supported"
 71→  | "internal_error";
 72→
 73→// ---------------------------------------------------------------------------
 74→// Frame types — discriminated union on the "type" field
 75→// ---------------------------------------------------------------------------
 76→
 77→export type RequestFrame = {
 78→  readonly type: "req";
 79→  readonly id: string;
 80→  readonly method: MethodName;
 81→  readonly params?: unknown;
 82→};
 83→
 84→export type GatewayError = {
 85→  readonly code: ErrorCode;
 86→  readonly message: string;
 87→  readonly details?: unknown;
 88→};
 89→
 90→export type ResponseFrame =
 91→  | {
 92→      readonly type: "res";
 93→      readonly id: string;
 94→      readonly ok: true;
 95→      readonly payload?: unknown;
 96→    }
 97→  | {
 98→      readonly type: "res";
 99→      readonly id: string;
100→      readonly ok: false;
101→      readonly error: GatewayError;
102→    };
103→
104→export type EventFrame = {
105→  readonly type: "event";
106→  readonly event: string;
107→  readonly payload?: unknown;
108→  readonly seq?: number;
109→};
110→
111→export type GatewayFrame = RequestFrame | ResponseFrame | EventFrame;
112→
113→// ---------------------------------------------------------------------------
114→// Pure parser — string to GatewayFrame | { error: string }
115→// ---------------------------------------------------------------------------
116→
117→export type ParseError = { readonly parseError: string };
118→
119→export function parseFrame(raw: string): GatewayFrame | ParseError {
120→  let parsed: unknown;
121→  try {
122→    parsed = JSON.parse(raw);
123→  } catch {
124→    return { parseError: "Failed to parse JSON frame" };
125→  }
126→
127→  if (typeof parsed !== "object" || parsed === null) {
128→    return { parseError: "Frame must be a JSON object" };
129→  }
130→
131→  const obj = parsed as Record<string, unknown>;
132→  const frameType = obj.type;
133→
134→  if (frameType === "req") {
135→    return parseRequestFrame(obj);
136→  }
137→  if (frameType === "res") {
138→    return parseResponseFrame(obj);
139→  }
140→  if (frameType === "event") {
141→    return parseEventFrame(obj);
142→  }
143→
144→  return { parseError: `Unknown frame type: ${String(frameType)}` };
145→}
146→
147→export function isParseError(result: GatewayFrame | ParseError): result is ParseError {
148→  return "parseError" in result;
149→}
150→
151→function parseRequestFrame(obj: Record<string, unknown>): RequestFrame | ParseError {
152→  if (typeof obj.id !== "string") {
153→    return { parseError: "Request frame missing required field: id" };
154→  }
155→  if (typeof obj.method !== "string") {
156→    return { parseError: "Request frame missing required field: method" };
157→  }
158→  const frame: RequestFrame = {
159→    type: "req",
160→    id: obj.id,
161→    method: obj.method as MethodName,
162→    ...(obj.params !== undefined ? { params: obj.params } : {}),
163→  };
164→  return frame;
165→}
166→
167→function parseResponseFrame(obj: Record<string, unknown>): ResponseFrame | ParseError {
168→  if (typeof obj.id !== "string") {
169→    return { parseError: "Response frame missing required field: id" };
170→  }
171→  if (typeof obj.ok !== "boolean") {
172→    return { parseError: "Response frame missing required field: ok" };
173→  }
174→
175→  if (obj.ok) {
176→    const frame: ResponseFrame = {
177→      type: "res",
178→      id: obj.id,
179→      ok: true,
180→      ...(obj.payload !== undefined ? { payload: obj.payload } : {}),
181→    };
182→    return frame;
183→  }
184→
185→  const frame: ResponseFrame = {
186→    type: "res",
187→    id: obj.id,
188→    ok: false,
189→    error: obj.error as GatewayError,
190→  };
191→  return frame;
192→}
193→
194→function parseEventFrame(obj: Record<string, unknown>): EventFrame | ParseError {
195→  if (typeof obj.event !== "string") {
196→    return { parseError: "Event frame missing required field: event" };
197→  }
198→  const frame: EventFrame = {
199→    type: "event",
200→    event: obj.event,
201→    ...(obj.payload !== undefined ? { payload: obj.payload } : {}),
202→    ...(obj.seq !== undefined ? { seq: obj.seq as number } : {}),
203→  };
204→  return frame;
205→}
206→
207→// ---------------------------------------------------------------------------
208→// Pure serializer — GatewayFrame to JSON string
209→// ---------------------------------------------------------------------------
210→
211→export function serializeFrame(frame: GatewayFrame): string {
212→  return JSON.stringify(frame);
213→}
