  1→/**
  2→ * Gateway connection state machine — pure transition function.
  3→ *
  4→ * No IO, no side effects, no imports from IO modules.
  5→ * The state machine models the lifecycle of a single WebSocket connection
  6→ * through the Gateway Protocol v3.
  7→ *
  8→ * transition(connection, event) => TransitionResult
  9→ *
 10→ * Effects are returned as data — the caller (impure shell) interprets them.
 11→ */
 12→import type { ConnectionState, GatewayConnection } from "./types";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Connection events — inputs to the state machine
 16→// ---------------------------------------------------------------------------
 17→
 18→export type ConnectionEvent =
 19→  | { readonly type: "ws_open" }
 20→  | { readonly type: "ws_close"; readonly code: number; readonly reason: string }
 21→  | { readonly type: "ws_message"; readonly data: string };
 22→
 23→// ---------------------------------------------------------------------------
 24→// Connection effects — side effects described as data
 25→// ---------------------------------------------------------------------------
 26→
 27→export type ConnectionEffect =
 28→  | { readonly type: "send_frame"; readonly frame: string }
 29→  | { readonly type: "close_connection"; readonly code: number; readonly reason: string }
 30→  | { readonly type: "start_keepalive" }
 31→  | { readonly type: "stop_keepalive" }
 32→  | { readonly type: "emit_presence"; readonly status: string }
 33→  | { readonly type: "record_trace"; readonly method: string; readonly connectionId: string };
 34→
 35→// ---------------------------------------------------------------------------
 36→// Transition result — new connection state + effects to execute
 37→// ---------------------------------------------------------------------------
 38→
 39→export type TransitionResult = {
 40→  readonly connection: GatewayConnection;
 41→  readonly effects: readonly ConnectionEffect[];
 42→};
 43→
 44→// ---------------------------------------------------------------------------
 45→// Factory — create a new connection in "connecting" state
 46→// ---------------------------------------------------------------------------
 47→
 48→export function createConnection(): GatewayConnection {
 49→  return {
 50→    connectionId: crypto.randomUUID(),
 51→    state: "connecting",
 52→    createdAt: Date.now(),
 53→    seqCounter: 0,
 54→    activeSessions: new Set<string>(),
 55→  };
 56→}
 57→
 58→// ---------------------------------------------------------------------------
 59→// Pure transition function
 60→// ---------------------------------------------------------------------------
 61→
 62→export function transition(
 63→  connection: GatewayConnection,
 64→  event: ConnectionEvent,
 65→): TransitionResult {
 66→  switch (connection.state) {
 67→    case "connecting":
 68→      return transitionFromConnecting(connection, event);
 69→    case "authenticating":
 70→      return transitionFromAuthenticating(connection, event);
 71→    case "active":
 72→      return transitionFromActive(connection, event);
 73→    case "closed":
 74→      return transitionFromClosed(connection);
 75→  }
 76→}
 77→
 78→// ---------------------------------------------------------------------------
 79→// Per-state transition handlers
 80→// ---------------------------------------------------------------------------
 81→
 82→function transitionFromConnecting(
 83→  connection: GatewayConnection,
 84→  event: ConnectionEvent,
 85→): TransitionResult {
 86→  switch (event.type) {
 87→    case "ws_open":
 88→      return {
 89→        connection: withState(connection, "authenticating"),
 90→        effects: [
 91→          { type: "record_trace", method: "ws_open", connectionId: connection.connectionId },
 92→        ],
 93→      };
 94→    case "ws_close":
 95→      return toClosedState(connection);
 96→    case "ws_message":
 97→      // Messages before ws_open are invalid — ignore
 98→      return { connection, effects: [] };
 99→  }
100→}
101→
102→function transitionFromAuthenticating(
103→  connection: GatewayConnection,
104→  event: ConnectionEvent,
105→): TransitionResult {
106→  switch (event.type) {
107→    case "ws_close":
108→      return toClosedState(connection);
109→    case "ws_message":
110→      // Authentication message handling will be added in step 01-03
111→      return { connection, effects: [] };
112→    case "ws_open":
113→      // Already opened — ignore duplicate
114→      return { connection, effects: [] };
115→  }
116→}
