118→function transitionFromActive(
119→  connection: GatewayConnection,
120→  event: ConnectionEvent,
121→): TransitionResult {
122→  switch (event.type) {
123→    case "ws_close":
124→      return {
125→        connection: withState(connection, "closed"),
126→        effects: [
127→          { type: "stop_keepalive" },
128→          { type: "emit_presence", status: "offline" },
129→          { type: "record_trace", method: "ws_close", connectionId: connection.connectionId },
130→        ],
131→      };
132→    case "ws_message":
133→      // Message dispatch will be added in step 01-03
134→      return { connection, effects: [] };
135→    case "ws_open":
136→      // Already opened — ignore
137→      return { connection, effects: [] };
