 16→  // Connection & auth
 17→  | "connect"
 18→  | "connect.verify"
 19→  // Agent execution
 20→  | "agent"
 21→  // Session management (OpenClaw sessions.* namespace)
 22→  | "sessions.list"
 23→  | "sessions.history"
 24→  | "sessions.send"
 25→  | "sessions.patch"
 26→  // Backward compat aliases
 27→  | "agent.status"
