  1→/**
  2→ * Gateway — public API for route registration and WebSocket handler config.
  3→ *
  4→ * The gateway is a thin protocol adapter at /api/gateway. Non-WebSocket
  5→ * requests receive 426 Upgrade Required. WebSocket connections enter the
  6→ * Gateway Protocol v3 state machine.
  7→ *
  8→ * Pure core (connection.ts) handles state transitions. This module is the
  9→ * impure shell that wires Bun's WebSocket handlers to the pure state machine.
 10→ */
 11→import { jsonResponse } from "../http/response";
 12→import { createConnection, transition } from "./connection";
 13→import type { GatewayConnection } from "./types";
 14→import type { Server } from "bun";
 15→
 16→// ---------------------------------------------------------------------------
 17→// WebSocket data attached to each connection via server.upgrade()
 18→// ---------------------------------------------------------------------------
 19→
 20→export type GatewayWebSocketData = {
 21→  readonly connection: GatewayConnection;
 22→};
 23→
 24→// ---------------------------------------------------------------------------
 25→// Route handler — upgrades WebSocket or returns 426
 26→// ---------------------------------------------------------------------------
 27→
 28→function handleGatewayRequest(
 29→  request: Request,
 30→  server: Server<GatewayWebSocketData>,
 31→): Response | undefined {
 32→  // Check for WebSocket upgrade header
 33→  const upgradeHeader = request.headers.get("upgrade");
 34→  if (upgradeHeader?.toLowerCase() === "websocket") {
 35→    const connection = createConnection();
 36→    const upgraded = server.upgrade(request, {
 37→      data: { connection },
 38→    });
 39→    if (upgraded) {
 40→      // Return undefined to signal Bun that the upgrade was handled
 41→      return undefined;
 42→    }
 43→    // Upgrade failed — fall through to 426
 44→  }
 45→
 46→  return jsonResponse(
 47→    { error: "upgrade_required", message: "This endpoint requires a WebSocket connection" },
 48→    426,
 49→  );
 50→}
 51→
 52→// ---------------------------------------------------------------------------
 53→// WebSocket handlers — Bun.serve websocket config
 54→// ---------------------------------------------------------------------------
 55→
 56→export function createGatewayWebSocketHandlers() {
 57→  return {
 58→    open(ws: { data: GatewayWebSocketData; send: (msg: string) => void }) {
 59→      const { connection } = ws.data;
 60→      const result = transition(connection, { type: "ws_open" });
 61→      // Update the connection state on the ws data (Bun allows mutation of ws.data)
 62→      (ws.data as { connection: GatewayConnection }).connection = result.connection;
 63→    },
 64→
 65→    message(
 66→      ws: { data: GatewayWebSocketData; send: (msg: string) => void },
 67→      message: string | Buffer,
 68→    ) {
 69→      const { connection } = ws.data;
 70→      const data = typeof message === "string" ? message : message.toString();
 71→      const result = transition(connection, { type: "ws_message", data });
 72→      (ws.data as { connection: GatewayConnection }).connection = result.connection;
 73→
 74→      // Process effects — message dispatch will be implemented in step 01-03
 75→      for (const effect of result.effects) {
 76→        if (effect.type === "send_frame") {
 77→          ws.send(effect.frame);
 78→        }
 79→      }
 80→    },
 81→
 82→    close(
 83→      ws: { data: GatewayWebSocketData },
 84→      code: number,
 85→      reason: string,
 86→    ) {
 87→      const { connection } = ws.data;
 88→      const result = transition(connection, { type: "ws_close", code, reason });
 89→      (ws.data as { connection: GatewayConnection }).connection = result.connection;
 90→    },
 91→  };
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Public API — route registration record for Bun.serve routes object
 96→// ---------------------------------------------------------------------------
 97→
 98→export function createGatewayRoutes() {
 99→  return {
100→    "/api/gateway": {
101→      GET: handleGatewayRequest,
102→    },
103→  } as const;
104→}
