335→// ---------------------------------------------------------------------------
336→// createOrchestratorSession
337→// ---------------------------------------------------------------------------
338→
339→type CreateSessionInput = {
340→  surreal: Surreal;
341→  shellExec: ShellExec;
342→  brainBaseUrl: string;
343→  brainIdentityId?: string;
344→  brainEnv?: Record<string, string>;
345→  anthropicBaseUrl?: string;
346→  anthropicCustomHeaders?: string;
347→  workspaceId: string;
348→  taskId: string;
349→  intentId?: string;
350→  authToken?: string;
351→  spawnAgent?: SpawnAgentFn;
352→  validateAssignment: (
353→    surreal: Surreal,
354→    workspaceId: string,
355→    taskId: string,
356→  ) => Promise<AssignmentResult>;
357→  createAgentSession: (input: {
358→    surreal: Surreal;
359→    agent: string;
360→    workspaceRecord: RecordId<"workspace", string>;
361→    taskId?: string;
362→  }) => Promise<{ session_id: string }>;
363→};
364→
365→export async function createOrchestratorSession(
366→  input: CreateSessionInput,
367→): Promise<OrchestratorSessionResult> {
368→  // 0. Intent authorization gate (optional — backwards compatible)
369→  if (input.intentId) {
370→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
371→    if (!gateResult.ok) {
372→      return { ok: false, error: gateResult.error };
373→    }
374→  }
375→
376→  // 1. Validate assignment eligibility
377→  const assignmentResult = await input.validateAssignment(
378→    input.surreal,
379→    input.workspaceId,
380→    input.taskId,
381→  );
382→
383→  if (!assignmentResult.ok) {
384→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
385→  }
386→
387→  const { validation } = assignmentResult;
388→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
389→  const repoRoot = validation.repoPath;
390→
391→  // 2. Create worktree
392→  const worktreeResult = await createWorktree(
393→    input.shellExec,
394→    repoRoot,
395→    taskSlug,
396→  );
397→
398→  if (!worktreeResult.ok) {
399→    return {
400→      ok: false,
401→      error: worktreeError(worktreeResult.error.message),
402→    };
403→  }
404→
405→  const { branchName, worktreePath } = worktreeResult.value;
406→
407→  // 3. Create agent_session record
408→  const { session_id: agentSessionId } = await input.createAgentSession({
409→    surreal: input.surreal,
410→    agent: "claude-agent-sdk",
411→    workspaceRecord: validation.workspaceRecord,
412→    taskId: input.taskId,
413→  });
414→
415→  const streamId = generateStreamId(agentSessionId);
416→  const anthropicCustomHeaders = input.anthropicCustomHeaders
417→    ? appendOrchestratorProxyHeaders(
418→        input.anthropicCustomHeaders,
419→        input.taskId,
420→        agentSessionId,
421→      )
422→    : undefined;
423→
424→  // 4. Build config and spawn agent
425→  const agentSpawnConfig: AgentSpawnConfig = {
426→    prompt: `/brain-start-task ${input.taskId}`,
427→    workDir: worktreePath,
428→    workspaceId: input.workspaceId,
429→    brainBaseUrl: input.brainBaseUrl,
430→    brainIdentityId: input.brainIdentityId,
431→    brainEnv: input.brainEnv,
432→    anthropicBaseUrl: input.anthropicBaseUrl,
433→    anthropicCustomHeaders,
434→  };
435→
436→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
437→  let handle: AgentHandle;
438→  try {
439→    handle = spawnFn(agentSpawnConfig);
440→  } catch (err) {
441→    // Rollback: remove worktree and delete agent_session on spawn failure
442→    await removeWorktree(input.shellExec, repoRoot, branchName);
443→    const sessionRecord = new RecordId("agent_session", agentSessionId);
444→    await input.surreal.delete(sessionRecord);
445→    return {
446→      ok: false,
447→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
448→    };
449→  }
450→
451→  // 5. Register handle for later abort
452→  handleRegistry.set(agentSessionId, handle);
453→
454→  // 6. Update agent_session with orchestrator fields
455→  const sessionRecord = new RecordId("agent_session", agentSessionId);
456→  await input.surreal.update(sessionRecord).merge({
457→    orchestrator_status: "spawning" as OrchestratorStatus,
458→    worktree_branch: branchName,
459→    worktree_path: worktreePath,
460→    stream_id: streamId,
461→  });
462→
463→  // 7. Transition intent to executing and create gates relation
464→  if (input.intentId) {
465→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
466→  }
467→
468→  return {
469→    ok: true,
470→    value: {
471→      agentSessionId,
472→      streamId,
473→      worktreeBranch: branchName,
474→    },
475→  };
476→}
