589→// ---------------------------------------------------------------------------
590→// abortOrchestratorSession
591→// ---------------------------------------------------------------------------
592→
593→type AbortSessionInput = {
594→  surreal: Surreal;
595→  shellExec: ShellExec;
596→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
597→  sessionId: string;
598→  endAgentSession: (input: {
599→    surreal: Surreal;
600→    workspaceRecord: RecordId<"workspace", string>;
601→    sessionId: string;
602→    summary: string;
603→  }) => Promise<{ session_id: string; ended: boolean }>;
604→};
605→
606→export async function abortOrchestratorSession(
607→  input: AbortSessionInput,
608→): Promise<AbortSessionResult> {
609→  const lookup = await lookupSession(input.surreal, input.sessionId);
610→  if (!lookup.ok) {
611→    return { ok: false, error: lookup.error };
612→  }
613→  const { session, record: sessionRecord } = lookup;
614→
615→  // 1. Abort the agent process if handle exists
616→  const handle = handleRegistry.get(input.sessionId);
617→  if (handle) {
618→    handle.abort();
619→    handleRegistry.delete(input.sessionId);
620→  }
621→
622→  // 2. Update orchestrator_status to aborted
623→  await input.surreal.update(sessionRecord).merge({
624→    orchestrator_status: "aborted" as OrchestratorStatus,
625→  });
626→
627→  const workspaceRecord = requireWorkspace(session, input.sessionId);
628→
629→  // 3. Remove worktree if branch name exists
630→  if (session.worktree_branch) {
631→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
632→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
633→  }
634→
635→  // 4. Return task to ready
636→  if (session.task_id) {
637→    await input.surreal.update(session.task_id).merge({
638→      status: "ready",
639→      updated_at: new Date(),
640→    });
641→  }
642→
643→  // 5. End the agent session
644→  await input.endAgentSession({
645→    surreal: input.surreal,
646→    workspaceRecord,
647→    sessionId: input.sessionId,
648→    summary: "Session aborted",
649→  });
650→
651→  return {
652→    ok: true,
653→    value: {
654→      aborted: true,
655→      sessionId: input.sessionId,
656→    },
657→  };
658→}
