717→// State guard helpers
718→// ---------------------------------------------------------------------------
719→
720→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
721→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
722→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
723→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
724→
725→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
726→  return {
727→    code: "SESSION_ERROR",
728→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
729→    httpStatus: 409,
730→  };
731→}
732→
733→function sessionAborted(sessionId: string): SessionError {
734→  return {
735→    code: "SESSION_ERROR",
736→    message: `Session ${sessionId} has been aborted`,
737→    httpStatus: 409,
738→  };
739→}
