741→// ---------------------------------------------------------------------------
742→// getOrchestratorReview
743→// ---------------------------------------------------------------------------
744→
745→type GetReviewInput = {
746→  surreal: Surreal;
747→  sessionId: string;
748→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
749→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
750→  getTaskTitle: (taskId: string) => Promise<string>;
751→};
752→
753→export async function getOrchestratorReview(
754→  input: GetReviewInput,
755→): Promise<ReviewResult> {
756→  const lookup = await lookupSession(input.surreal, input.sessionId);
757→  if (!lookup.ok) {
758→    return { ok: false, error: lookup.error };
759→  }
760→  const { session, status } = lookup;
761→
762→  if (status === "aborted") {
763→    return { ok: false, error: sessionAborted(input.sessionId) };
764→  }
765→
766→  if (!REVIEWABLE_STATUSES.has(status)) {
767→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
768→  }
769→
770→  // Get diff from the branch
771→  const branchName = session.worktree_branch ?? "";
772→  const workspaceRecord = requireWorkspace(session, input.sessionId);
773→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
774→  const diffResult = await input.getDiff(repoRoot, branchName);
775→
776→  const diff = diffResult.ok
777→    ? diffResult.value
778→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
779→
780→  // Get task title
781→  const taskId = session.task_id ? session.task_id.id : "";
782→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
783→
784→  return {
785→    ok: true,
786→    value: {
787→      taskTitle,
788→      diff,
789→      session: {
790→        orchestratorStatus: status,
791→        ...pickDefined({
792→          worktreeBranch: session.worktree_branch,
793→          startedAt: session.started_at,
794→          lastEventAt: session.last_event_at,
795→        }),
796→      },
797→    },
798→  };
799→}
