801→// ---------------------------------------------------------------------------
802→// rejectOrchestratorSession
803→// ---------------------------------------------------------------------------
804→
805→type RejectSessionInput = {
806→  surreal: Surreal;
807→  sessionId: string;
808→  feedback: string;
809→};
810→
811→export async function rejectOrchestratorSession(
812→  input: RejectSessionInput,
813→): Promise<RejectSessionResult> {
814→  const lookup = await lookupSession(input.surreal, input.sessionId);
815→  if (!lookup.ok) {
816→    return { ok: false, error: lookup.error };
817→  }
818→  const { session, record: sessionRecord, status } = lookup;
819→
820→  if (!REJECTABLE_STATUSES.has(status)) {
821→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
822→  }
823→
824→  // 1. Update session status to active (agent resumes work)
825→  await input.surreal.update(sessionRecord).merge({
826→    orchestrator_status: "active" as OrchestratorStatus,
827→    last_feedback: input.feedback,
828→  });
829→
830→  // 2. Return task to in_progress
831→  if (session.task_id) {
832→    await input.surreal.update(session.task_id).merge({
833→      status: "in_progress",
834→      updated_at: new Date(),
835→    });
836→  }
837→
838→  return {
839→    ok: true,
840→    value: {
841→      rejected: true,
842→      continuing: true,
843→    },
844→  };
845→}
