329→// ---------------------------------------------------------------------------
330→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
331→// ---------------------------------------------------------------------------
332→
333→export type OrchestratorWiringDeps = {
334→  surreal: import("surrealdb").Surreal;
335→  shellExec: import("./worktree-manager").ShellExec;
336→  brainBaseUrl: string;
337→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
338→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
339→  sseRegistry?: SseRegistry;
340→  queryFn: import("./spawn-agent").QueryFn;
341→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
342→  mockAgent: boolean;
343→};
344→
345→export function wireOrchestratorRoutes(
346→  wiringDeps: OrchestratorWiringDeps,
347→): {
348→  assign: RouteHandler;
349→  status: RouteHandler;
350→  accept: RouteHandler;
351→  abort: RouteHandler;
352→  review: RouteHandler;
353→  reject: RouteHandler;
354→  prompt: RouteHandler;
355→  stream?: RouteHandler;
356→} {
357→  const proxyTokenTtlDays = readProxyTokenTtlDays();
358→
359→  const issueProxyTokenForWorkspace = async (
360→    workspaceId: string,
361→    authToken: string,
362→  ): Promise<{ proxyToken: string; identityId: string }> => {
363→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
364→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
365→    const personId = session?.user?.id;
366→    if (!personId) {
367→      throw new Error("Failed to issue proxy token: authentication required");
368→    }
369→
370→    const personRecord = new RecordId("person", personId);
371→    const workspaceRecord = new RecordId("workspace", workspaceId);
372→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
373→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
374→      { person: personRecord, ws: workspaceRecord },
375→    );
376→    const identityRecord = identityRows[0];
377→    if (!identityRecord) {
378→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
379→    }
380→    const identityId = identityRecord.id as string;
381→
382→    const rawToken = generateProxyToken();
383→    const tokenHash = hashProxyToken(rawToken);
384→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
385→
386→    await wiringDeps.surreal.query(
387→      `BEGIN TRANSACTION;
388→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
389→       CREATE proxy_token CONTENT {
390→         token_hash: $hash,
391→         workspace: $ws,
392→         identity: $identity,
393→         expires_at: $expires,
394→         created_at: time::now(),
395→         revoked: false
396→       };
397→       COMMIT TRANSACTION;`,
398→      {
399→        hash: tokenHash,
400→        ws: workspaceRecord,
401→        identity: identityRecord,
402→        expires: expiresAt,
403→      },
404→    );
405→
406→    return { proxyToken: rawToken, identityId };
407→  };
408→
409→  const issueBrainMcpAuthEnv = async (
410→    workspaceId: string,
411→    identityId: string,
412→    intentGoal: string,
413→    intentReasoning: string,
414→  ): Promise<Record<string, string>> => {
415→    const dpopKeys = await generateKeyPair();
416→    const intentResult = await submitIntentForAuthorization(
417→      {
418→        workspace_id: workspaceId,
419→        identity_id: identityId,
420→        authorization_details: CLI_AUTHORIZATION_DETAILS,
421→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
422→        goal: intentGoal,
423→        reasoning: intentReasoning,
424→      },
425→      {
426→        surreal: wiringDeps.surreal,
427→        extractionModel: wiringDeps.extractionModel,
428→      },
429→    );
430→
431→    let intentStatus: string = intentResult.status;
432→    if (intentStatus === "pending_auth") {
433→      const evaluation = await evaluatePendingIntent(
434→        intentResult.intentId,
435→        {
436→          surreal: wiringDeps.surreal,
437→          extractionModel: wiringDeps.extractionModel,
438→          llmEvaluator: async () => ({
439→            decision: "APPROVE",
440→            risk_score: 0,
441→            reason: "Approved from explicit authenticated orchestrator task assignment",
442→            reasoning:
443→              "User explicitly assigned this task in the orchestrator UI. " +
444→              "Bootstrap MCP token is required to complete the assigned task.",
445→          }),
446→        },
447→      );
448→      if (!evaluation.ok) {
449→        throw new Error(
450→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
451→        );
452→      }
453→      intentStatus = evaluation.value.status;
454→    }
455→
456→    if (intentStatus !== "authorized") {
457→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
458→    }
459→
460→    const tokenResult = await exchangeIntentForToken({
461→      surreal: wiringDeps.surreal,
462→      asSigningKey: wiringDeps.asSigningKey,
463→      intentId: intentResult.intentId,
464→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
465→      proofThumbprint: dpopKeys.thumbprint,
466→    });
467→
468→    if (!tokenResult.ok) {
469→      throw new Error(
470→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
471→      );
472→    }
473→
474→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
475→
476→    return {
477→      BRAIN_CLIENT_ID: "orchestrator-session",
478→      BRAIN_ACCESS_TOKEN: "orchestrator-session",
479→      BRAIN_REFRESH_TOKEN: "orchestrator-session",
480→      BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
481→      BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
482→      BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
483→      BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
484→      BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
485→      BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
486→    };
487→  };
488→
489→  // Workspace access guard — resolves user from session cookie, checks membership
490→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
491→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
492→    if (!session?.user?.id) {
493→      return jsonError("authentication required", 401);
494→    }
495→    const { RecordId } = await import("surrealdb");
496→    const personRecord = new RecordId("person", session.user.id);
497→    const workspaceRecord = new RecordId("workspace", workspaceId);
498→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
499→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
500→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
501→      { person: personRecord, ws: workspaceRecord },
502→    );
503→    if (!memberRows || memberRows.length === 0) {
504→      return jsonError("not a member of this workspace", 403);
505→    }
506→    return undefined;
507→  };
508→
509→  // Lazy imports to keep module boundary clean
510→  const lifecycleImport = import("./session-lifecycle");
511→  const queriesImport = import("../mcp/mcp-queries");
512→  const guardImport = import("./assignment-guard");
513→  const stallDetectorImport = import("./stall-detector");
514→
515→  // Helper: resolve repo_path from workspace record
516→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
517→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
518→      `SELECT repo_path FROM $ws;`,
519→      { ws: workspaceRecord },
520→    );
521→    const repoPath = rows[0]?.repo_path;
522→    if (!repoPath) {
523→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
524→    }
525→    return repoPath;
526→  };
527→
528→  const buildTaskScopedIntentContext = async (
529→    taskId: string,
530→  ): Promise<{ goal: string; reasoning: string }> => {
531→    const taskRecord = new RecordId("task", taskId);
532→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
533→      `SELECT title, description FROM $task LIMIT 1;`,
534→      { task: taskRecord },
535→    );
536→    const taskTitle = taskRows[0]?.title?.trim();
537→    const taskDescription = taskRows[0]?.description?.trim();
538→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
539→    const descriptionSuffix = taskDescription && taskDescription.length > 0
540→      ? ` Task description: ${taskDescription}`
541→      : "";
542→
543→    return {
544→      goal: `Complete task: ${taskLabel}`,
545→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
546→    };
547→  };
548→
549→  // Use mock spawn for acceptance tests, production spawn otherwise
550→  const spawnAgentImport = wiringDeps.mockAgent
551→    ? Promise.resolve({
