/**
 * Unit tests for the method-dispatch pure routing table.
 *
 * The dispatch function maps MethodName to handler functions.
 * Unknown or unsupported methods return method_not_supported.
 */
import { describe, expect, it } from "bun:test";
import {
  createMethodDispatch,
  type MethodHandler,
  type MethodHandlerContext,
} from "../../../app/src/server/gateway/method-dispatch";
import type { GatewayConnection } from "../../../app/src/server/gateway/types";

// ---------------------------------------------------------------------------
// Stub handler factory
// ---------------------------------------------------------------------------

function stubHandler(name: string): MethodHandler {
  return async (_conn, _params, _deps) => ({
    ok: true as const,
    payload: { handler: name },
  });
}

function stubConnection(overrides?: Partial<GatewayConnection>): GatewayConnection {
  return {
    connectionId: "test-conn-id",
    state: "active",
    createdAt: Date.now(),
    seqCounter: 0,
    activeSessions: new Set(),
    ...overrides,
  };
}

const stubDeps = {} as MethodHandlerContext["deps"];

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("createMethodDispatch", () => {
  const connectHandler = stubHandler("connect");
  const agentHandler = stubHandler("agent");

  const dispatch = createMethodDispatch({
    connect: connectHandler,
    agent: agentHandler,
  });

  it("routes 'connect' to the connect handler", async () => {
    const result = await dispatch("connect", stubConnection(), {}, stubDeps);
    expect(result.ok).toBe(true);
    if (result.ok) {
      expect((result.payload as { handler: string }).handler).toBe("connect");
    }
  });

  it("routes 'agent' to the agent handler", async () => {
    const result = await dispatch("agent", stubConnection(), {}, stubDeps);
    expect(result.ok).toBe(true);
    if (result.ok) {
      expect((result.payload as { handler: string }).handler).toBe("agent");
    }
  });

  it("returns method_not_supported for unknown methods", async () => {
    const result = await dispatch(
      "sessions.list" as any,
      stubConnection(),
      {},
      stubDeps,
    );
    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.code).toBe("method_not_supported");
    }
  });

  it("returns method_not_supported for unregistered methods", async () => {
    const result = await dispatch(
      "tools.catalog" as any,
      stubConnection(),
      {},
      stubDeps,
    );
    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.code).toBe("method_not_supported");
    }
  });
});

/**
 * Gateway method dispatch — pure routing table.
 *
 * Maps MethodName to handler functions. Each handler receives the connection,
 * params, and deps, returning a ResponsePayload. Unregistered methods produce
 * method_not_supported errors.
 *
 * No IO, no side effects, no imports from IO modules.
 */
import type { MethodName, GatewayError } from "./protocol";
import type { GatewayConnection, GatewayDeps } from "./types";

// ---------------------------------------------------------------------------
// Handler types
// ---------------------------------------------------------------------------

export type ResponsePayload =
  | { readonly ok: true; readonly payload?: unknown }
  | { readonly ok: false; readonly error: GatewayError };

export type MethodHandlerContext = {
  readonly deps: GatewayDeps;
};

export type MethodHandler = (
  connection: GatewayConnection,
  params: unknown,
  deps: GatewayDeps,
) => Promise<ResponsePayload>;

// ---------------------------------------------------------------------------
// Dispatch table factory
// ---------------------------------------------------------------------------

export type MethodHandlerMap = Partial<Record<MethodName, MethodHandler>>;

export type DispatchFn = (
  method: MethodName,
  connection: GatewayConnection,
  params: unknown,
  deps: GatewayDeps,
) => Promise<ResponsePayload>;

/**
 * Create a dispatch function from a partial handler map.
 * Methods not in the map return method_not_supported.
 */
export function createMethodDispatch(
  handlers: MethodHandlerMap,
): DispatchFn {
  return async (method, connection, params, deps) => {
    const handler = handlers[method];
    if (!handler) {
      return {
        ok: false,
        error: {
          code: "method_not_supported",
          message: `Method "${method}" is not supported`,
        },
      };
    }
    return handler(connection, params, deps);
  };
}

/**
 * Connect method handler — skeleton auth support.
 *
 * The connect handler authenticates the client and transitions the connection
 * to active state. For the walking skeleton, it recognizes a hardcoded
 * "skeleton-test-token" and bypasses Ed25519 verification.
 *
 * Returns a HelloOk payload with protocol info, policy, and auth details.
 */
import type { MethodHandler, ResponsePayload } from "../method-dispatch";
import type { GatewayConnection } from "../types";

// ---------------------------------------------------------------------------
// Skeleton auth constants
// ---------------------------------------------------------------------------

const SKELETON_AUTH_TOKEN = "skeleton-test-token";
const SKELETON_WORKSPACE_ID = "skeleton-test-ws";
const SKELETON_IDENTITY_ID = "skeleton-test-identity";
const SKELETON_AGENT_ID = "skeleton-test-agent";

// ---------------------------------------------------------------------------
// Connect params shape
// ---------------------------------------------------------------------------

type ConnectParams = {
  readonly minProtocol?: number;
  readonly maxProtocol?: number;
  readonly client?: {
    readonly id?: string;
    readonly version?: string;
    readonly platform?: string;
    readonly mode?: string;
  };
  readonly role?: string;
  readonly scopes?: readonly string[];
  readonly auth?: {
    readonly token?: string;
  };
  readonly device?: {
    readonly id?: string;
    readonly publicKey?: string;
    readonly signature?: string;
    readonly signedAt?: number;
    readonly nonce?: string;
  };
};

// ---------------------------------------------------------------------------
// HelloOk payload
// ---------------------------------------------------------------------------

type HelloOkPayload = {
  readonly protocol: number;
  readonly policy: {
    readonly tickIntervalMs: number;
  };
  readonly auth: {
    readonly deviceToken: string;
    readonly role: string;
    readonly scopes: readonly string[];
  };
  readonly workspace: {
    readonly id: string;
  };
  readonly identity: {
    readonly id: string;
    readonly agentId: string;
  };
};

// ---------------------------------------------------------------------------
// Connection state transition helper
// ---------------------------------------------------------------------------

export type ConnectionUpdate = {
  readonly state: "active";
  readonly identityId: string;
  readonly workspaceId: string;
  readonly agentId: string;
};

export type ConnectResult = {
  readonly response: ResponsePayload;
  readonly connectionUpdate?: ConnectionUpdate;
};

// ---------------------------------------------------------------------------
// Handler
// ---------------------------------------------------------------------------

function isSkeletonAuth(params: ConnectParams): boolean {
  return params.auth?.token === SKELETON_AUTH_TOKEN;
}

function buildHelloOkPayload(
  role: string,
  scopes: readonly string[],
  workspaceId: string,
  identityId: string,
  agentId: string,
): HelloOkPayload {
  return {
    protocol: 3,
    policy: { tickIntervalMs: 15_000 },
    auth: {
      deviceToken: "skeleton-device-token",
      role,
      scopes,
    },
    workspace: { id: workspaceId },
    identity: { id: identityId, agentId },
  };
}

/**
 * Handle the connect method. Returns both a response payload and an optional
 * connection state update for the caller to apply.
 */
export function createConnectHandler(): {
  handler: MethodHandler;
} {
  const handler: MethodHandler = async (connection, params, _deps) => {
    const connectParams = (params ?? {}) as ConnectParams;

    // Already authenticated — reject duplicate connect
    if (connection.state === "active") {
      return {
        ok: false,
        error: {
          code: "already_authenticated",
          message: "Connection is already authenticated",
        },
      };
    }

    // Skeleton auth bypass
    if (isSkeletonAuth(connectParams)) {
      const role = connectParams.role ?? "operator";
      const scopes = connectParams.scopes ?? [];
      const payload = buildHelloOkPayload(
        role,
        scopes,
        SKELETON_WORKSPACE_ID,
        SKELETON_IDENTITY_ID,
        SKELETON_AGENT_ID,
      );
      return { ok: true, payload };
    }

    // Real Ed25519 auth — not yet implemented
    return {
      ok: false,
      error: {
        code: "auth_failed",
        message: "Ed25519 authentication not yet implemented",
      },
    };
  };

  return { handler };
}

/**
 * Determine connection state update from connect params.
 * Separated from handler for pure state machine usage.
 */
export function resolveConnectionUpdate(
  params: unknown,
): ConnectionUpdate | undefined {
  const connectParams = (params ?? {}) as ConnectParams;
  if (isSkeletonAuth(connectParams)) {
    return {
      state: "active",
      identityId: SKELETON_IDENTITY_ID,
      workspaceId: SKELETON_WORKSPACE_ID,
      agentId: SKELETON_AGENT_ID,
    };
  }
  return undefined;
}

/**
 * Agent method handler — delegates to the orchestrator.
 *
 * Validates the task param, loads workspace context summary,
 * assigns the task to create a session, and returns the run details.
 */
import type { MethodHandler } from "../method-dispatch";

// ---------------------------------------------------------------------------
// Agent params shape
// ---------------------------------------------------------------------------

type AgentParams = {
  readonly task?: string;
  readonly model?: string;
  readonly maxTokens?: number;
};

// ---------------------------------------------------------------------------
// Handler
// ---------------------------------------------------------------------------

export function createAgentHandler(): MethodHandler {
  return async (connection, params, deps) => {
    const agentParams = (params ?? {}) as AgentParams;

    if (!agentParams.task || agentParams.task.trim() === "") {
      return {
        ok: false,
        error: {
          code: "invalid_frame",
          message: "agent method requires a 'task' parameter",
        },
      };
    }

    // Connection must have workspace and identity from connect auth
    if (!connection.workspaceId || !connection.identityId) {
      return {
        ok: false,
        error: {
          code: "not_authenticated",
          message: "Connection is not authenticated — send connect first",
        },
      };
    }

    const workspaceId = connection.workspaceId;
    const identityId = connection.identityId;
    const task = agentParams.task.trim();

    // Load context summary from workspace
    const contextSummary = await deps.loadContext(workspaceId, task);

    // Assign task to create session
    const { runId, sessionId } = await deps.assignTask(
      workspaceId,
      identityId,
      task,
      agentParams.model || agentParams.maxTokens
        ? {
            model: agentParams.model,
            maxTokens: agentParams.maxTokens,
          }
        : undefined,
    );

    return {
      ok: true,
      payload: {
        runId,
        sessionId,
        contextSummary,
      },
    };
  };
}

