  1→/**
  2→ * Gateway — public API for route registration and WebSocket handler config.
  3→ *
  4→ * The gateway is a thin protocol adapter at /api/gateway. Non-WebSocket
  5→ * requests receive 426 Upgrade Required. WebSocket connections enter the
  6→ * Gateway Protocol v3 state machine.
  7→ *
  8→ * Pure core (connection.ts) handles state transitions. This module is the
  9→ * impure shell that wires Bun's WebSocket handlers to the pure state machine.
 10→ */
 11→import { jsonResponse } from "../http/response";
 12→import { createConnection, transition, activateConnection } from "./connection";
 13→import { parseFrame, isParseError, serializeFrame } from "./protocol";
 14→import type { ResponseFrame } from "./protocol";
 15→import { createMethodDispatch, type MethodHandlerMap } from "./method-dispatch";
 16→import { createConnectHandler, resolveConnectionUpdate } from "./method-handlers/connect";
 17→import { createAgentHandler } from "./method-handlers/agent";
 18→import type { GatewayConnection, GatewayDeps } from "./types";
 19→import type { Server } from "bun";
 20→
 21→// ---------------------------------------------------------------------------
 22→// WebSocket data attached to each connection via server.upgrade()
 23→// ---------------------------------------------------------------------------
 24→
 25→export type GatewayWebSocketData = {
 26→  readonly connection: GatewayConnection;
 27→  readonly deps: GatewayDeps;
 28→};
 29→
 30→// ---------------------------------------------------------------------------
 31→// Route handler — upgrades WebSocket or returns 426
 32→// ---------------------------------------------------------------------------
 33→
 34→function createGatewayRequestHandler(deps: GatewayDeps) {
 35→  return function handleGatewayRequest(
 36→    request: Request,
 37→    server: Server<GatewayWebSocketData>,
 38→  ): Response | undefined {
 39→    // Check for WebSocket upgrade header
 40→    const upgradeHeader = request.headers.get("upgrade");
 41→    if (upgradeHeader?.toLowerCase() === "websocket") {
 42→      const connection = createConnection();
 43→      const upgraded = server.upgrade(request, {
 44→        data: { connection, deps },
 45→      });
 46→      if (upgraded) {
 47→        // Return undefined to signal Bun that the upgrade was handled
 48→        return undefined;
 49→      }
 50→      // Upgrade failed — fall through to 426
 51→    }
 52→
 53→    return jsonResponse(
 54→      { error: "upgrade_required", message: "This endpoint requires a WebSocket connection" },
 55→      426,
 56→    );
 57→  };
 58→}
 59→
 60→// ---------------------------------------------------------------------------
 61→// Method handler registry
 62→// ---------------------------------------------------------------------------
 63→
 64→function buildHandlerMap(): MethodHandlerMap {
 65→  const { handler: connectHandler } = createConnectHandler();
 66→  const agentHandler = createAgentHandler();
 67→
 68→  return {
 69→    connect: connectHandler,
 70→    agent: agentHandler,
 71→  };
 72→}
 73→
 74→// ---------------------------------------------------------------------------
 75→// WebSocket handlers — Bun.serve websocket config
 76→// ---------------------------------------------------------------------------
 77→
 78→export function createGatewayWebSocketHandlers() {
 79→  const dispatch = createMethodDispatch(buildHandlerMap());
 80→
 81→  return {
 82→    open(ws: { data: GatewayWebSocketData; send: (msg: string) => void }) {
 83→      const { connection } = ws.data;
 84→      const result = transition(connection, { type: "ws_open" });
 85→      (ws.data as { connection: GatewayConnection; deps: GatewayDeps }).connection = result.connection;
 86→    },
 87→
 88→    message(
 89→      ws: { data: GatewayWebSocketData; send: (msg: string) => void },
 90→      message: string | Buffer,
 91→    ) {
 92→      const rawData = typeof message === "string" ? message : message.toString();
 93→      const { connection, deps } = ws.data;
 94→
 95→      // Parse frame
 96→      const parsed = parseFrame(rawData);
 97→      if (isParseError(parsed)) {
 98→        const errorResponse: ResponseFrame = {
 99→          type: "res",
100→          id: "unknown",
101→          ok: false,
102→          error: {
103→            code: "invalid_frame",
104→            message: parsed.parseError,
105→          },
106→        };
107→        ws.send(serializeFrame(errorResponse));
108→        return;
109→      }
110→
111→      // Only handle request frames
112→      if (parsed.type !== "req") {
113→        return;
114→      }
115→
116→      const requestFrame = parsed;
117→
118→      // State guard: methods other than "connect" require active state
119→      if (requestFrame.method !== "connect" && connection.state !== "active") {
120→        const notAuthResponse: ResponseFrame = {
121→          type: "res",
122→          id: requestFrame.id,
123→          ok: false,
124→          error: {
125→            code: "not_authenticated",
126→            message: "Connection is not authenticated — send connect first",
127→          },
128→        };
129→        ws.send(serializeFrame(notAuthResponse));
130→        return;
131→      }
132→
133→      // Dispatch to handler (async)
134→      dispatch(requestFrame.method, connection, requestFrame.params, deps)
135→        .then((result) => {
136→          // Build response frame
137→          const responseFrame: ResponseFrame = result.ok
138→            ? { type: "res", id: requestFrame.id, ok: true, payload: result.payload }
139→            : { type: "res", id: requestFrame.id, ok: false, error: result.error };
140→
141→          ws.send(serializeFrame(responseFrame));
142→
143→          // If connect succeeded, transition connection to active
144→          if (requestFrame.method === "connect" && result.ok) {
145→            const update = resolveConnectionUpdate(requestFrame.params);
146→            if (update) {
147→              (ws.data as { connection: GatewayConnection; deps: GatewayDeps }).connection =
148→                activateConnection(connection, update);
149→            }
150→          }
151→        })
152→        .catch((err) => {
153→          const errorResponse: ResponseFrame = {
154→            type: "res",
155→            id: requestFrame.id,
156→            ok: false,
157→            error: {
158→              code: "internal_error",
159→              message: err instanceof Error ? err.message : "Internal error",
160→            },
161→          };
162→          ws.send(serializeFrame(errorResponse));
163→        });
164→    },
165→
166→    close(
167→      ws: { data: GatewayWebSocketData },
168→      code: number,
169→      reason: string,
170→    ) {
171→      const { connection } = ws.data;
172→      const result = transition(connection, { type: "ws_close", code, reason });
173→      (ws.data as { connection: GatewayConnection; deps: GatewayDeps }).connection = result.connection;
174→    },
175→  };
176→}
