179→// Public API — route registration record for Bun.serve routes object
180→// ---------------------------------------------------------------------------
181→
182→export function createGatewayRoutes(deps: GatewayDeps) {
183→  return {
184→    "/api/gateway": {
185→      GET: createGatewayRequestHandler(deps),
186→    },
187→  } as const;
188→}
