18→
19→// ---------------------------------------------------------------------------
20→// Handler
21→// ---------------------------------------------------------------------------
22→
23→export function createAgentHandler(): MethodHandler {
24→  return async (connection, params, deps) => {
25→    const agentParams = (params ?? {}) as AgentParams;
26→
27→    if (!agentParams.task || agentParams.task.trim() === "") {
28→      return {
29→        ok: false,
30→        error: {
31→          code: "invalid_frame",
32→          message: "agent method requires a 'task' parameter",
33→        },
34→      };
35→    }
36→
37→    // Connection must have workspace and identity from connect auth
38→    if (!connection.workspaceId || !connection.identityId) {
39→      return {
40→        ok: false,
41→        error: {
42→          code: "not_authenticated",
43→          message: "Connection is not authenticated — send connect first",
44→        },
45→      };
46→    }
47→
48→    const workspaceId = connection.workspaceId;
49→    const identityId = connection.identityId;
50→    const task = agentParams.task.trim();
51→
52→    // Load context summary from workspace
53→    const contextSummary = await deps.loadContext(workspaceId, task);
54→
55→    // Assign task to create session
56→    const { runId, sessionId } = await deps.assignTask(
57→      workspaceId,
58→      identityId,
59→      task,
60→      agentParams.model || agentParams.maxTokens
61→        ? {
62→            model: agentParams.model,
63→            maxTokens: agentParams.maxTokens,
64→          }
65→        : undefined,
66→    );
67→
68→    return {
69→      ok: true,
70→      payload: {
71→        runId,
72→        sessionId,
73→        contextSummary,
74→      },
75→    };
76→  };
77→}
