  1→/**
  2→ * Event bridge: transforms Claude Agent SDK messages into Brain StreamEvent
  3→ * variants and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (transformSdkMessage) + effectful bridge handle
  6→ * (startEventBridge) that manages the event forwarding lifecycle.
  7→ */
  8→import type {
  9→  AgentTokenEvent,
 10→  AgentFileChangeEvent,
 11→  AgentStatusEvent,
 12→  StreamEvent,
 13→} from "../../shared/contracts";
 14→import type { StallDetectorHandle } from "./stall-detector";
 15→import { log } from "../telemetry/logger";
 16→
 17→// ---------------------------------------------------------------------------
 18→// SDK message types (from @anthropic-ai/claude-code)
 19→// ---------------------------------------------------------------------------
 20→
 21→export type ContentBlock =
 22→  | { type: "text"; text: string }
 23→  | { type: "tool_use"; id: string; name: string; input: Record<string, unknown> }
 24→  | { type: "tool_result"; tool_use_id: string; content: string };
 25→
 26→export type SdkMessage =
 27→  | {
 28→      type: "assistant";
 29→      content?: unknown;
 30→      message?: {
 31→        content?: unknown;
 32→      };
 33→    }
 34→  | { type: "result"; subtype: "success"; duration_ms: number }
 35→  | { type: "result"; subtype: "error"; error: string }
 36→  | { type: "system"; subtype: string; [key: string]: unknown }
 37→  | { type: "user" };
 38→
 39→// ---------------------------------------------------------------------------
 40→// Port: dependencies as function signatures
 41→// ---------------------------------------------------------------------------
 42→
 43→export type EventBridgeDeps = {
 44→  emitEvent: (streamId: string, event: StreamEvent) => void;
 45→  updateLastEventAt: (sessionId: string) => Promise<void>;
 46→};
 47→
 48→// ---------------------------------------------------------------------------
 49→// Bridge handle
 50→// ---------------------------------------------------------------------------
 51→
 52→export type EventBridgeHandle = {
 53→  handleMessage: (message: SdkMessage) => void;
 54→  stop: () => void;
 55→};
 56→
 57→// ---------------------------------------------------------------------------
 58→// File operation tool detection
 59→// ---------------------------------------------------------------------------
 60→
 61→/** Tool names that represent file write/edit operations. */
 62→const FILE_WRITE_TOOLS = new Set(["Write"]);
 63→const FILE_EDIT_TOOLS = new Set(["Edit"]);
 64→
 65→function isFileOperationTool(toolName: string): boolean {
 66→  return FILE_WRITE_TOOLS.has(toolName) || FILE_EDIT_TOOLS.has(toolName);
 67→}
 68→
 69→function extractFileChangeType(toolName: string): AgentFileChangeEvent["changeType"] {
 70→  if (FILE_WRITE_TOOLS.has(toolName)) return "created";
 71→  if (FILE_EDIT_TOOLS.has(toolName)) return "modified";
 72→  return "modified";
 73→}
 74→
 75→function extractFilePath(input: Record<string, unknown>): string | undefined {
 76→  if (typeof input.file_path === "string") return input.file_path;
 77→  return undefined;
 78→}
 79→
 80→// ---------------------------------------------------------------------------
 81→// Pure transform: SDK message -> Brain StreamEvent[]
 82→// ---------------------------------------------------------------------------
 83→
 84→function transformTextBlock(
 85→  block: { type: "text"; text: string },
 86→  sessionId: string,
 87→): AgentTokenEvent {
 88→  return {
 89→    type: "agent_token",
 90→    sessionId,
 91→    token: block.text,
 92→  };
 93→}
 94→
 95→function transformToolUseBlock(
 96→  block: { type: "tool_use"; id: string; name: string; input: Record<string, unknown> },
 97→  sessionId: string,
 98→): AgentFileChangeEvent | undefined {
 99→  if (!isFileOperationTool(block.name)) return undefined;
100→
101→  const filePath = extractFilePath(block.input);
102→  if (!filePath) return undefined;
103→
104→  return {
105→    type: "agent_file_change",
106→    sessionId,
107→    file: filePath,
108→    changeType: extractFileChangeType(block.name),
109→  };
110→}
111→
112→function transformAssistantContent(
113→  content: ContentBlock[],
114→  sessionId: string,
115→): StreamEvent[] {
116→  const events: StreamEvent[] = [];
117→  for (const block of content) {
118→    if (block.type === "text") {
119→      events.push(transformTextBlock(block, sessionId));
120→    } else if (block.type === "tool_use") {
121→      const fileEvent = transformToolUseBlock(block, sessionId);
122→      if (fileEvent) events.push(fileEvent);
123→    }
124→  }
125→  return events;
126→}
127→
128→function toContentBlocks(content: unknown): ContentBlock[] {
129→  if (!Array.isArray(content)) return [];
130→
131→  const blocks: ContentBlock[] = [];
132→  for (const raw of content) {
133→    if (typeof raw !== "object" || raw === null) continue;
134→    const block = raw as {
135→      type?: unknown;
136→      text?: unknown;
137→      id?: unknown;
138→      name?: unknown;
139→      input?: unknown;
140→      tool_use_id?: unknown;
141→      content?: unknown;
142→    };
143→
144→    if (block.type === "text" && typeof block.text === "string") {
145→      blocks.push({ type: "text", text: block.text });
146→      continue;
147→    }
148→
149→    if (
150→      block.type === "tool_use"
151→      && typeof block.id === "string"
152→      && typeof block.name === "string"
153→      && typeof block.input === "object"
154→      && block.input !== null
155→    ) {
156→      blocks.push({
157→        type: "tool_use",
158→        id: block.id,
159→        name: block.name,
160→        input: block.input as Record<string, unknown>,
161→      });
162→      continue;
163→    }
164→
165→    if (
166→      block.type === "tool_result"
167→      && typeof block.tool_use_id === "string"
168→      && typeof block.content === "string"
169→    ) {
170→      blocks.push({
171→        type: "tool_result",
172→        tool_use_id: block.tool_use_id,
173→        content: block.content,
174→      });
175→    }
176→  }
177→
178→  return blocks;
179→}
180→
181→function extractAssistantContent(message: {
182→  content?: unknown;
183→  message?: {
184→    content?: unknown;
185→  };
186→}): ContentBlock[] {
187→  const direct = toContentBlocks(message.content);
188→  if (direct.length > 0) return direct;
189→  return toContentBlocks(message.message?.content);
190→}
191→
192→function transformResultMessage(
193→  message: { type: "result"; subtype: "success"; duration_ms: number } | { type: "result"; subtype: "error"; error: string },
194→  sessionId: string,
195→): AgentStatusEvent {
196→  if (message.subtype === "error") {
197→    return {
198→      type: "agent_status",
199→      sessionId,
200→      status: "error",
201→      error: message.error,
202→    };
203→  }
204→  return {
205→    type: "agent_status",
206→    sessionId,
207→    status: "completed",
208→  };
209→}
210→
211→/** System subtypes that carry no user-visible information and should be suppressed. */
212→const SUPPRESSED_SYSTEM_SUBTYPES = new Set([
213→  "init",
214→  "task_started",
215→  "task_progress",
216→]);
217→
218→function transformSystemMessage(
219→  message: { type: "system"; subtype: string; [key: string]: unknown },
220→  sessionId: string,
221→): AgentTokenEvent | undefined {
222→  const subtype = message.subtype;
223→
224→  if (SUPPRESSED_SYSTEM_SUBTYPES.has(subtype)) return undefined;
225→
226→  if (subtype === "mcp_server_error") {
227→    const server = (message as Record<string, unknown>).server_name ?? "unknown";
228→    const error = (message as Record<string, unknown>).error ?? "";
229→    return { type: "agent_token", sessionId, token: `[system] MCP server "${server}" failed: ${error}\n` };
230→  }
231→
232→  // Surface other system subtypes as informational tokens
233→  return { type: "agent_token", sessionId, token: `[system] ${subtype}\n` };
234→}
235→
236→export function transformSdkMessage(
237→  message: SdkMessage,
238→  sessionId: string,
239→): StreamEvent[] {
240→  switch (message.type) {
241→    case "assistant":
242→      return transformAssistantContent(extractAssistantContent(message), sessionId);
243→
244→    case "result":
245→      return [transformResultMessage(message, sessionId)];
246→
247→    case "system": {
248→      const event = transformSystemMessage(message, sessionId);
249→      return event ? [event] : [];
250→    }
251→
252→    default:
253→      return [];
254→  }
255→}
