257→// ---------------------------------------------------------------------------
258→// Step event detection for stall detector
259→// ---------------------------------------------------------------------------
260→
261→/** Returns true if the message contains tool_use blocks for file operations. */
262→function containsFileOperationStep(message: SdkMessage): boolean {
263→  if (message.type !== "assistant") return false;
264→  const content = extractAssistantContent(message);
265→  return content.some(
266→    (block) => block.type === "tool_use" && isFileOperationTool(block.name),
267→  );
268→}
